/*
 * MESI Cache Coherence Protocol Implementation
 * Demonstrates state transitions for a 2-processor system
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/* MESI Protocol States */
typedef enum {
 INVALID = 0,
 EXCLUSIVE,
 SHARED,
 MODIFIED
} MESI_State;

/* State names for display */
const char* state_names[] = {"Invalid", "Exclusive", "Shared", "Modified"};

/* Cache line structure */
typedef struct {
 int address;
 int data;
 MESI_State state;
 int dirty; /* 1 if modified but not written back */
} CacheLine;

/* Processor cache structure */
typedef struct {
 int processor_id;
 CacheLine *lines;
 int cache_size;
 int hits;
 int misses;
} ProcessorCache;

/* Shared memory (main memory) */
int main_memory[16] = {0};

/* Bus transactions log */
#define MAX_TRANSACTIONS 100
char bus_transactions[MAX_TRANSACTIONS][128];
int transaction_count = 0;

/* Initialize processor cache */
ProcessorCache* init_cache(int processor_id, int size) {
 ProcessorCache *cache = (ProcessorCache*)malloc(sizeof(ProcessorCache));
 cache->processor_id = processor_id;
 cache->cache_size = size;
 cache->lines = (CacheLine*)malloc(sizeof(CacheLine) * size);
 cache->hits = 0;
 cache->misses = 0;

 /* Initialize all lines to invalid */
 for (int i = 0; i < size; i++) {
 cache->lines[i].address = -1;
 cache->lines[i].data = 0;
 cache->lines[i].state = INVALID;
 cache->lines[i].dirty = 0;
 }
 return cache;
}

/* Log bus transaction */
void log_transaction(const char *fmt, ...) {
 if (transaction_count < MAX_TRANSACTIONS) {
 va_list args;
 va_start(args, fmt);
 vsnprintf(bus_transactions[transaction_count], 128, fmt, args);
 va_end(args);
 transaction_count++;
 }
}

/* Find cache line by address (returns index or -1) */
int find_line(ProcessorCache *cache, int address) {
 for (int i = 0; i < cache->cache_size; i++) {
 if (cache->lines[i].address == address) {
 return i;
 }
 }
 return -1;
}

/* Find free cache line */
int find_free_line(ProcessorCache *cache) {
 for (int i = 0; i < cache->cache_size; i++) {
 if (cache->lines[i].state == INVALID) {
 return i;
 }
 }
 return 0; /* Simple: evict first line if full */
}

/* Evict cache line if necessary */
void evict_line(ProcessorCache *cache, int line_idx) {
 CacheLine *line = &cache->lines[line_idx];

 if (line->state == MODIFIED) {
 /* Write back to memory */
 log_transaction("P%d: Write back addr=%d (value=%d) to memory", 
 cache->processor_id, line->address, line->data);
 main_memory[line->address] = line->data;
 }

 line->state = INVALID;
 line->address = -1;
 line->dirty = 0;
}

/* Check if other caches have valid copy of address */
int other_caches_have_copy(ProcessorCache **all_caches, int num_caches, 
 int my_id, int address) {
 for (int i = 0; i < num_caches; i++) {
 if (i != my_id) {
 int line_idx = find_line(all_caches[i], address);
 if (line_idx >= 0 && all_caches[i]->lines[line_idx].state != INVALID) {
 return 1;
 }
 }
 }
 return 0;
}

/* Invalidate all other caches' copies */
void invalidate_others(ProcessorCache **all_caches, int num_caches, 
 int my_id, int address) {
 for (int i = 0; i < num_caches; i++) {
 if (i != my_id) {
 int line_idx = find_line(all_caches[i], address);
 if (line_idx >= 0 && all_caches[i]->lines[line_idx].state != INVALID) {
 /* Write back if modified */
 if (all_caches[i]->lines[line_idx].state == MODIFIED) {
 main_memory[address] = all_caches[i]->lines[line_idx].data;
 log_transaction("P%d: Write back to memory before invalidate", i);
 }
 all_caches[i]->lines[line_idx].state = INVALID;
 log_transaction("P%d: Invalidate copy of addr=%d", i, address);
 }
 }
 }
}

/* MESI Protocol: Read operation */
int mesi_read(ProcessorCache **all_caches, int num_caches, int processor_id, int address) {
 ProcessorCache *cache = all_caches[processor_id];
 int line_idx = find_line(cache, address);

 printf("P%d: READ request for address %d\n", processor_id, address);

 if (line_idx >= 0 && cache->lines[line_idx].state != INVALID) {
 /* Cache hit */
 cache->hits++;
 printf(" -> Cache hit! State: %s, Data: %d\n", 
 state_names[cache->lines[line_idx].state], 
 cache->lines[line_idx].data);

 /* Transition from Modified to Shared on read by same processor */
 if (cache->lines[line_idx].state == MODIFIED) {
 cache->lines[line_idx].state = SHARED;
 printf(" -> State transition: MODIFIED -> SHARED\n");
 }
 return cache->lines[line_idx].data;
 }

 /* Cache miss - need to fetch */
 cache->misses++;

 /* Check if another cache has the line */
 int has_copy = other_caches_have_copy(all_caches, num_caches, processor_id, address);

 /* Evict if necessary */
 if (line_idx < 0) {
 line_idx = find_free_line(cache);
 evict_line(cache, line_idx);
 } else if (cache->lines[line_idx].state != INVALID) {
 evict_line(cache, line_idx);
 }

 /* Fetch data */
 int data = main_memory[address];

 log_transaction("P%d: BusRd for addr=%d (has_copy=%d)", processor_id, address, has_copy);

 /* Invalidate others if they have modified copy */
 invalidate_others(all_caches, num_caches, processor_id, address);

 /* Set line state based on whether others have copies */
 cache->lines[line_idx].address = address;
 cache->lines[line_idx].data = data;
 cache->lines[line_idx].state = has_copy ? SHARED : EXCLUSIVE;
 cache->lines[line_idx].dirty = 0;

 printf(" -> Cache miss! Fetched from memory. State: %s, Data: %d\n",
 state_names[cache->lines[line_idx].state], data);

 return data;
}

/* MESI Protocol: Write operation */
void mesi_write(ProcessorCache **all_caches, int num_caches, int processor_id, 
 int address, int value) {
 ProcessorCache *cache = all_caches[processor_id];
 int line_idx = find_line(cache, address);

 printf("P%d: WRITE request for address %d = %d\n", processor_id, address, value);

 if (line_idx >= 0 && cache->lines[line_idx].state != INVALID) {
 /* Can write directly */
 if (cache->lines[line_idx].state == EXCLUSIVE) {
 cache->lines[line_idx].state = MODIFIED;
 printf(" -> State transition: EXCLUSIVE -> MODIFIED\n");
 } else if (cache->lines[line_idx].state == SHARED) {
 /* Need to invalidate others */
 log_transaction("P%d: BusUpgr (invalidate) for addr=%d", processor_id, address);
 invalidate_others(all_caches, num_caches, processor_id, address);
 cache->lines[line_idx].state = MODIFIED;
 printf(" -> State transition: SHARED -> MODIFIED (invalidated others)\n");
 }

 cache->lines[line_idx].data = value;
 cache->lines[line_idx].dirty = 1;
 main_memory[address] = value;
 printf(" -> Write complete! Data: %d, State: %s\n",
 value, state_names[cache->lines[line_idx].state]);
 } else {
 /* Need to get exclusive ownership first (BusRdX) */
 cache->misses++;

 /* Evict if necessary */
 if (line_idx < 0) {
 line_idx = find_free_line(cache);
 evict_line(cache, line_idx);
 }

 log_transaction("P%d: BusRdX (read with intent to modify) for addr=%d", 
 processor_id, address);

 /* Invalidate all other caches */
 invalidate_others(all_caches, num_caches, processor_id, address);

 /* Set line */
 cache->lines[line_idx].address = address;
 cache->lines[line_idx].data = value;
 cache->lines[line_idx].state = MODIFIED;
 cache->lines[line_idx].dirty = 1;
 main_memory[address] = value;

 printf(" -> Got exclusive ownership! State: MODIFIED, Data: %d\n", value);
 }
}

/* Print cache state */
void print_cache_state(ProcessorCache *cache) {
 printf("P%d Cache State: ", cache->processor_id);
 for (int i = 0; i < cache->cache_size; i++) {
 if (cache->lines[i].state != INVALID) {
 printf("[Addr=%d: %s, Data=%d] ",
 cache->lines[i].address,
 state_names[cache->lines[i].state],
 cache->lines[i].data);
 }
 }
 printf("\n");
}

/* Print all caches state */
void print_all_caches(ProcessorCache **caches, int num_caches) {
 printf("\n=== Cache States ===\n");
 for (int i = 0; i < num_caches; i++) {
 print_cache_state(caches[i]);
 }
 printf("====================\n\n");
}

int main() {
 const int NUM_PROCESSORS = 2;
 const int CACHE_SIZE = 4;

 /* Initialize memory */
 main_memory[100] = 5;
 printf("Initial memory: X[100] = %d\n\n", main_memory[100]);

 /* Create caches */
 ProcessorCache **caches = (ProcessorCache**)malloc(sizeof(ProcessorCache*) * NUM_PROCESSORS);
 for (int i = 0; i < NUM_PROCESSORS; i++) {
 caches[i] = init_cache(i, CACHE_SIZE);
 }

 printf("=== Step 1: Both processors read X (initial access) ===\n");
 mesi_read(caches, NUM_PROCESSORS, 0, 100); // P0 reads - becomes Exclusive
 mesi_read(caches, NUM_PROCESSORS, 1, 100); // P1 reads - becomes Shared
 print_all_caches(caches, NUM_PROCESSORS);

 printf("=== Step 2: P0 writes X = 10 (write-invalidate) ===\n");
 mesi_write(caches, NUM_PROCESSORS, 0, 100, 10); // P0 writes - invalidates P1
 print_all_caches(caches, NUM_PROCESSORS);

 printf("=== Step 3: P1 reads X (should get updated value) ===\n");
 mesi_read(caches, NUM_PROCESSORS, 1, 100); // P1 reads - fetches updated value
 print_all_caches(caches, NUM_PROCESSORS);

 printf("=== Bus Transactions Log ===\n");
 for (int i = 0; i < transaction_count; i++) {
 printf(" %s\n", bus_transactions[i]);
 }

 /* Performance stats */
 printf("\n=== Performance Statistics ===\n");
 for (int i = 0; i < NUM_PROCESSORS; i++) {
 int total = caches[i]->hits + caches[i]->misses;
 double hit_rate = total > 0 ? (double)caches[i]->hits / total * 100 : 0;
 printf("P%d: Hits=%d, Misses=%d, Hit Rate=%.1f%%\n",
 i, caches[i]->hits, caches[i]->misses, hit_rate);
 }

 /* Cleanup */
 for (int i = 0; i < NUM_PROCESSORS; i++) {
 free(caches[i]->lines);
 free(caches[i]);
 }
 free(caches);

 return 0;
}
